DELETE FROM payments
WHERE booking_id IN (
    SELECT id FROM bookings
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
);

DELETE FROM booking_seats
WHERE booking_id IN (
    SELECT id FROM bookings
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
);

DELETE FROM snack_order_items
WHERE snack_order_id IN (
    SELECT id FROM snack_orders
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
);

DELETE FROM combo_items
WHERE combo_id IN (
    SELECT id FROM combos
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
)
OR snack_id IN (
    SELECT id FROM snacks
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
);

DELETE FROM snack_order_items
WHERE snack_id IN (
    SELECT id FROM snacks
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
)
OR combo_id IN (
    SELECT id FROM combos
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
);

DELETE FROM showtimes
WHERE room_id IN (
    SELECT id FROM rooms
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
);

DELETE FROM seats
WHERE room_id IN (
    SELECT id FROM rooms
    WHERE theater_id NOT IN (SELECT id FROM theaters WHERE code = N'CNX-HN')
);

DELETE FROM refresh_tokens
WHERE user_id IN (
    SELECT id FROM users
    WHERE role IN (N'SUPER_ADMIN', N'ADMIN')
      AND username <> N'cinex.hn'
);

DELETE FROM password_reset_tokens
WHERE user_id IN (
    SELECT id FROM users
    WHERE role IN (N'SUPER_ADMIN', N'ADMIN')
      AND username <> N'cinex.hn'
);

DELETE FROM email_verification_tokens
WHERE user_id IN (
    SELECT id FROM users
    WHERE role IN (N'SUPER_ADMIN', N'ADMIN')
      AND username <> N'cinex.hn'
);

DELETE FROM notifications
WHERE user_id IN (
    SELECT id FROM users
    WHERE role IN (N'SUPER_ADMIN', N'ADMIN')
      AND username <> N'cinex.hn'
);

DELETE FROM user_favorites
WHERE user_id IN (
    SELECT id FROM users
    WHERE role IN (N'SUPER_ADMIN', N'ADMIN')
      AND username <> N'cinex.hn'
);

DELETE FROM reviews
WHERE user_id IN (
    SELECT id FROM users
    WHERE role IN (N'SUPER_ADMIN', N'ADMIN')
      AND username <> N'cinex.hn'
);

DELETE FROM users
WHERE role IN (N'SUPER_ADMIN', N'ADMIN')
  AND username <> N'cinex.hn';
